import type {PropsWithChildren} from 'react';

import {SidebarProvider} from '@/components/ui/sidebar';
import {cn} from '@/lib/utils';

type AppLayoutProps = PropsWithChildren<{
  className?: string;
}>;

/**
 * Root layout shell for Docker app pages.
 *
 * Renders a full-screen flex row via SidebarProvider. Place AppSidebar
 * and AppContent as direct children — AppSidebar on the left, AppContent
 * filling the remaining space. AppHeader goes inside AppContent.
 *
 * ```tsx
 * <AppLayout>
 *   <AppSidebar>{navItems}</AppSidebar>
 *   <AppContent>
 *     <AppHeader ... />
 *     <main>page content</main>
 *   </AppContent>
 * </AppLayout>
 * ```
 */
export const AppLayout = ({children, className}: AppLayoutProps) => {
  return (
    <SidebarProvider className={cn('bg-background text-foreground', className)}>
      {children}
    </SidebarProvider>
  );
};
